import java.util.Scanner;

public class ReservedInstanceRecommender {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter hourly on-demand rate (Rs.): ");
        double onDemandRate = scanner.nextDouble();

        System.out.print("Enter daily usage hours: ");
        double dailyHours = scanner.nextDouble();

        System.out.print("Enter expected usage period (months): ");
        int months = scanner.nextInt();

        // Calculate costs
        double onDemandMonthly = onDemandRate * dailyHours * 30;
        double onDemandTotal = onDemandMonthly * months;

        // Reserved Instance (1 year term, ~60% discount)
        double riUpfront = onDemandRate * dailyHours * 365 * 0.40; // 40% upfront
        double riMonthly = 0; // All upfront for 1 year
        double riTotal = riUpfront;

        double savings = onDemandTotal - riTotal;
        double savingsPercent = (savings / onDemandTotal) * 100;

        System.out.println("\n=== Analysis ===");
        System.out.println("On-Demand Total: Rs. " + onDemandTotal);
        System.out.println("Reserved Instance Total: Rs. " + riTotal);
        System.out.println("Potential Savings: Rs. " + savings + " (" + savingsPercent + "%)");

        if (savingsPercent > 30) {
            System.out.println("RECOMMENDATION: Use Reserved Instances - High savings!");
        } else if (savingsPercent > 15) {
            System.out.println("RECOMMENDATION: Consider Reserved Instances - Moderate savings");
        } else {
            System.out.println("RECOMMENDATION: Use On-Demand - Low savings from RI");
        }

        scanner.close();
    }
}
